Firestore Rules.rules_code:
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is authenticated
    function isAuthenticated() {
      return request.auth != null;
    }

    // Helper function to check if user owns the resource
    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // Applications collection - Users can ONLY access their own applications
    match /applications/{applicationId} {
      // Allow reading only if the application belongs to the authenticated user
      allow read: if isAuthenticated() && resource.data.userId == request.auth.uid;

      // Allow creating only if userId matches the authenticated user
      allow create: if isAuthenticated() && request.resource.data.userId == request.auth.uid;

      // Allow updating/deleting only if the application belongs to the user
      allow update, delete: if isAuthenticated() && resource.data.userId == request.auth.uid;
    }

    // Users collection - Users can ONLY access their own profile
    match /users/{userId} {
      // Users can only read their own profile
      allow read: if isOwner(userId);

      // Users can only create their own profile
      allow create: if isOwner(userId);

      // Users can only update their own profile
      allow update: if isOwner(userId);

      // Users cannot delete their own profile (prevents accidental deletion)
      allow delete: if false;
    }

    // Jobs collection - Read-only for authenticated users, admin-only for writes
    match /jobs/{jobId} {
      // Any authenticated user can read jobs
      allow read: if isAuthenticated();

      // Only admins can create, update, or delete jobs
      allow create, update, delete: if isAuthenticated() && request.auth.token.admin == true;
    }
  }
}

