{
  "rules": {

    // Users can only access their own user data
    "users": {
      "$uid": {
        ".read": "$uid === auth.uid",
        ".write": "$uid === auth.uid",
        ".validate": "newData.hasChildren(['profile', 'email']) || newData.hasChildren(['profile'])"
      }
    },

    // Users can only access their own status/presence data
    "status": {
      "$uid": {
        ".read": "$uid === auth.uid",
        ".write": "$uid === auth.uid"
      }
    },

    // Users can only access their own applications
    "applications": {
      "$uid": {
        ".read": "$uid === auth.uid",
        ".write": "$uid === auth.uid"
      }
    },

    // No access to any other paths by default
    "$other": {
      ".read": false,
      ".write": false
    }
  }
}
